import random, json, datetime

def maybe_log_for_eval(request, response, sample_rate=0.02):
    """Log ~2% of production traffic for offline eval."""
    if random.random() < sample_rate:
        entry = {
            "ts": datetime.datetime.utcnow().isoformat(),
            "input": request,
            "output": response,
            "labels": None,  # filled by labelers later
        }
        with open("eval_candidates.jsonl", "a") as f:
            f.write(json.dumps(entry) + "\n")
